const helmet = require('helmet');
app.use(helmet());
```

This sets headers like `X-Content-Type-Options`, `X-Frame-Options`, `Strict-Transport-Security`, and removes `X-Powered-By` automatically.

---

### 3. 🔒 No Rate Limiting
The `/users` endpoint (and any future routes) are open to brute-force and enumeration attacks. Add `express-rate-limit`:

```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }); // 100 req/15min
app.use(limiter);
```

---

### 4. ⚠️ No Global Error Handler
Unhandled errors will crash the process or leak stack traces to clients. Add a centralized error-handling middleware at the bottom:

```js
// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal Server Error' : err.message
  });
});
```

